import torch
from flask import Flask, request, jsonify
from PIL import Image
import io

app = Flask(__name__)

# Load your pre-trained model here
model = torch.load('path_to_your_model.pth')
model.eval()

def predict(image_bytes):
    image = Image.open(io.BytesIO(image_bytes))
    # Perform any necessary preprocessing (resize, normalize, etc.)
    # For example:
    # transform = transforms.Compose([
    #     transforms.Resize((256, 256)),
    #     transforms.ToTensor(),
    #     transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    # ])
    # image = transform(image).unsqueeze(0)
    
    with torch.no_grad():
        output = model(image)
        _, predicted_class = torch.max(output.data, 1)
        confidence_score = torch.softmax(output, dim=1)[0][predicted_class].item()
    
    return predicted_class.item(), confidence_score

@app.route('/predict', methods=['POST'])
def predict_route():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    if file and allowed_file(file.filename):
        image_bytes = file.read()
        predicted_class, confidence_score = predict(image_bytes)
        return jsonify({
            'predicted_class': predicted_class,
            'confidence_score': confidence_score
        }), 200

def allowed_file(filename):
    # Add your file extension validation here
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in {'png', 'jpg', 'jpeg'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)